using System;
using System.Collections.Generic;
using System.IO;
using System.Xml;
using DefusedXML;

public static Dictionary<string, string> ParseConfigFile(string filePath)
{
    // Disable external entity processing in XML parsers
    XmlReaderSettings settings = new XmlReaderSettings();
    settings.DtdProcessing = DtdProcessing.Prohibit;

    // Use DefusedXML to parse the XML and extract settings into a Dictionary
    using (var reader = XmlReader.Create(filePath, settings))
    {
        var doc = new XmlDocument();
        doc.Load(reader);

        var dict = new Dictionary<string, string>();
        foreach (XmlNode node in doc.SelectNodes("//setting"))
        {
            dict[node.Attributes["name"].Value] = node.InnerText;
        }

        return dict;
    }
